import React, { useState, useEffect, useRef } from 'react';
import { Link } from 'react-router-dom';
import adminService from '../../services/adminService';

const DASHBOARD_CACHE_KEY = 'admin_dashboard_cache_v2';

const EMPTY_DASHBOARD_DATA = {
    total_revenue: 0,
    total_orders: 0,
    total_products: 0,
    low_stock_products: [],
    recent_orders: [],
};

const readCachedDashboardData = () => {
    try {
        const raw = localStorage.getItem(DASHBOARD_CACHE_KEY);
        if (!raw) {
            return EMPTY_DASHBOARD_DATA;
        }

        const parsed = JSON.parse(raw);
        if (!parsed || typeof parsed !== 'object') {
            return EMPTY_DASHBOARD_DATA;
        }

        return {
            ...EMPTY_DASHBOARD_DATA,
            ...parsed,
            low_stock_products: Array.isArray(parsed.low_stock_products) ? parsed.low_stock_products : [],
            recent_orders: Array.isArray(parsed.recent_orders) ? parsed.recent_orders : [],
        };
    } catch {
        return EMPTY_DASHBOARD_DATA;
    }
};

export default function Dashboard() {
    const [dashData, setDashData] = useState(() => readCachedDashboardData());
    const [syncing, setSyncing] = useState(false);
    const [error, setError] = useState('');
    const requestIdRef = useRef(0);

    useEffect(() => {
        loadDashboardData();

        return () => {
            requestIdRef.current += 1;
        };
    }, []);

    const loadDashboardData = async () => {
        requestIdRef.current += 1;
        const requestId = requestIdRef.current;

        // Don't show loading - render with cache immediately
        try {
            const res = await Promise.race([
                adminService.getStats({ timeout: 5000 }),
                new Promise<any>((resolve) =>
                    setTimeout(() => resolve(null), 2500)
                ),
            ]);

            if (requestIdRef.current !== requestId || !res) {
                return;
            }

            const nextData = {
                ...EMPTY_DASHBOARD_DATA,
                ...(res?.data?.data || {}),
                low_stock_products: Array.isArray(res?.data?.data?.low_stock_products)
                    ? res.data.data.low_stock_products
                    : [],
                recent_orders: Array.isArray(res?.data?.data?.recent_orders)
                    ? res.data.data.recent_orders
                    : [],
            };

            setDashData(nextData);
            localStorage.setItem(DASHBOARD_CACHE_KEY, JSON.stringify(nextData));
        } catch {
            // Silently fail - keep showing cached data
        }
    };

    const formatCurrencyCompact = (value) => {
        if (value >= 1000000) {
            return `₱${(value / 1000000).toFixed(1)}M`;
        }
        if (value >= 1000) {
            return `₱${(value / 1000).toFixed(1)}k`;
        }
        return `₱${value.toFixed(0)}`;
    };

    const formatOrderAmount = (value) => {
        const num = parseFloat(value || 0);
        return `₱${num.toFixed(2)}`;
    };

    const formatOrderStatus = (status) => {
        const value = (status || 'pending').toLowerCase();
        if (value === 'completed') {
            return 'delivered';
        }
        if (value === 'processing') {
            return 'processing';
        }
        if (value === 'shipped') {
            return 'shipped';
        }
        if (value === 'cancelled') {
            return 'cancelled';
        }
        return 'pending';
    };

    const chartMonths = ['Oct', 'Nov', 'Dec', 'Jan', 'Feb', 'Mar'];
    const revenueSeries = [12000, 15400, 21200, 18700, 22400, 26900];
    const orderSeries = [45, 58, 73, 64, 82, 94];

    const linePoints = revenueSeries
        .map((value, index) => {
            const x = 40 + index * 110;
            const y = 210 - ((value - 10000) / (28000 - 10000)) * 170;
            return `${x},${y}`;
        })
        .join(' ');

    const maxOrders = Math.max(...orderSeries, 1);
    const lowStockProducts = [...(dashData.low_stock_products || [])]
        .sort((a, b) => Number(a.stock || 0) - Number(b.stock || 0));

    const statCards = [
        {
            label: 'Total Revenue',
            value: formatCurrencyCompact(parseFloat(dashData.total_revenue || 0)),
            icon: '₱',
            iconClass: 'stat-icon--green',
        },
        {
            label: 'Total Orders',
            value: `${dashData.total_orders || 0}`,
            icon: 'OR',
            iconClass: 'stat-icon--blue',
        },
        {
            label: 'Parts in Stock',
            value: `${dashData.total_products || 0}`,
            icon: 'PR',
            iconClass: 'stat-icon--purple',
        },
        {
            label: 'Low Stock Alert',
            value: `${dashData.low_stock_products.length || 0}`,
            icon: 'AL',
            iconClass: 'stat-icon--orange',
        },
    ];

    return (
        <div className="admin-page-content admin-dashboard-page">

            <section className="admin-stat-grid-modern">
                {statCards.map((card) => (
                    <article className="admin-stat-card-modern" key={card.label}>
                        <div>
                            <p className="label">{card.label}</p>
                            <h3>{card.value}</h3>
                        </div>
                        <div className={`stat-icon ${card.iconClass}`}>{card.icon}</div>
                    </article>
                ))}
            </section>

            <section className="admin-insight-grid">
                <article className="admin-insight-card">
                    <div className="low-stock-header">
                        <h2>Recent Orders</h2>
                        <Link to="/admin/orders" className="btn btn-outline btn-sm">Open Orders</Link>
                    </div>
                    <div className="insight-list">
                        {dashData.recent_orders.length > 0 ? (
                            dashData.recent_orders.slice(0, 5).map((order, index) => {
                                const status = formatOrderStatus(order.status || order.payment_status);
                                return (
                                    <div className="recent-order-item" key={order.id || index}>
                                        <div>
                                            <p className="order-id">{order.order_number || `ORD-${String(index + 1).padStart(3, '0')}`}</p>
                                            <p className="order-user">{order.user?.name || 'Customer'}</p>
                                        </div>
                                        <div className="order-meta">
                                            <p className="order-amount">{formatOrderAmount(order.total_amount)}</p>
                                            <span className={`order-status status-${status}`}>{status}</span>
                                        </div>
                                    </div>
                                );
                            })
                        ) : (
                            <p className="insight-empty">No recent orders found.</p>
                        )}
                    </div>
                </article>

                <article className="admin-insight-card">
                    <div className="low-stock-header">
                        <h2>Low Stock Alerts</h2>
                        <Link to="/admin/products" className="btn btn-outline btn-sm">Open Inventory</Link>
                    </div>
                    <div className="insight-list">
                        {lowStockProducts.length > 0 ? (
                            lowStockProducts.slice(0, 5).map((product, index) => (
                                <div className="stock-alert-item" key={product.id || index}>
                                    <div className="stock-alert-left">
                                        <span className="stock-alert-icon" aria-hidden="true">!</span>
                                        <div>
                                            <p className="stock-name">{product.name}</p>
                                            <p className="stock-sku">{product.sku || product.slug || `ITEM-${String(index + 1).padStart(3, '0')}`}</p>
                                        </div>
                                    </div>
                                    <strong className="stock-count">{product.stock} left</strong>
                                </div>
                            ))
                        ) : (
                            <p className="insight-empty">No low stock alerts right now.</p>
                        )}
                    </div>
                </article>
            </section>

            <section className="admin-chart-grid">
                <article className="admin-chart-card">
                    <h2>Revenue Overview</h2>
                    <svg viewBox="0 0 640 260" className="admin-chart-svg" aria-label="Revenue chart">
                        <line x1="40" y1="30" x2="40" y2="220" className="axis" />
                        <line x1="40" y1="220" x2="610" y2="220" className="axis" />
                        <polyline points={linePoints} className="line" />
                        {revenueSeries.map((value, index) => {
                            const x = 40 + index * 110;
                            const y = 210 - ((value - 10000) / (28000 - 10000)) * 170;
                            return <circle key={chartMonths[index]} cx={x} cy={y} r="4" className="dot" />;
                        })}
                        {chartMonths.map((month, index) => (
                            <text key={month} x={40 + index * 110} y="245" className="label">{month}</text>
                        ))}
                    </svg>
                </article>

                <article className="admin-chart-card">
                    <h2>Monthly Orders</h2>
                    <svg viewBox="0 0 640 260" className="admin-chart-svg" aria-label="Orders chart">
                        <line x1="40" y1="30" x2="40" y2="220" className="axis" />
                        <line x1="40" y1="220" x2="610" y2="220" className="axis" />
                        {orderSeries.map((value, index) => {
                            const x = 70 + index * 90;
                            const height = (value / maxOrders) * 160;
                            return (
                                <g key={chartMonths[index]}>
                                    <rect x={x} y={220 - height} width="56" height={height} className="bar" />
                                    <text x={x + 28} y="245" textAnchor="middle" className="label">{chartMonths[index]}</text>
                                </g>
                            );
                        })}
                    </svg>
                </article>
            </section>
        </div>
    );
}
